+/// A context variable that can have different values in different contexts
+pub fn ContextVar(comptime T: type) type {
+    return struct {
+        const Self = @This();
+
+        name: []const u8,
+        default: ?T,
+
+        // Thread-local storage for the value
+        value: std.Thread.LocalStorage(?T),
